async def main():
    async with async_session() as db:
        existing = await db.execute(select(Course).where(Course.title == COURSE_TITLE))
        if existing.scalar_one_or_none():
            print(f"Course '{COURSE_TITLE}' already exists — skipping.")
            return

        author_result = await db.execute(select(User).limit(1))
        author = author_result.scalar_one_or_none()
        if not author:
            print("No users found — create a user first.")
            return

        course = Course(
            title=COURSE_TITLE,
            slug="call-center-operator-" + uuid.uuid4().hex[:4],
            description=COURSE_DESC,
            author_id=author.id,
            category="Call Center",
            difficulty="Beginner",
            price=0,
            currency="USD",
            status="published",
        )
        db.add(course)
        await db.flush()

        nodes, edges = [], []
        lesson_counter = 0
        total_lessons = 0

        for sec_data in SECTIONS:
            section = CourseSection(
                course_id=course.id,
                title=sec_data["title"],
                position=sec_data["pos"],
            )
            db.add(section)
            await db.flush()

            for li, les_data in enumerate(sec_data["lessons"]):
                lesson = CourseLesson(
                    section_id=section.id,
                    title=les_data["t"],
                    position=li,
                    content_type="interactive",
                    content_markdown="",
                    xp_reward=les_data["xp"],
                    steps=les_data["steps"],
                )
                db.add(lesson)
                await db.flush()

                row = lesson_counter // 5
                col_idx = lesson_counter % 5
                x = SNAKE_X[col_idx] * CANVAS_W
                y = V_PAD + row * ROW_H
                nodes.append({"id": str(lesson.id), "x": x, "y": y})
                if lesson_counter > 0:
                    edges.append({
                        "id": f"e-{lesson_counter}",
                        "source": nodes[-2]["id"],
                        "target": nodes[-1]["id"],
                    })
                lesson_counter += 1
                total_lessons += 1

        course.roadmap_nodes = nodes
        course.roadmap_edges = edges
        await db.commit()

        section_count = len(SECTIONS)
        print(f"Created course '{COURSE_TITLE}': {section_count} sections, {total_lessons} lessons.")
        print("Seed complete!")


if __name__ == "__main__":
    asyncio.run(main())
